#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data (float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_iteration(const float* f_old, float* f, float* error_array) {
  int i = blockIdx.x * blockDim.x + threadIdx.x + 1;
  int j = blockIdx.y * blockDim.y + threadIdx.y + 1;

  if (i >= 1 && i <= N-2 && j >= 1 && j <= N-2) {
    float t = 0.25f * (f_old[IDX(i-1,j)] +
                       f_old[IDX(i+1,j)] +
                       f_old[IDX(i,j-1)] +
                       f_old[IDX(i,j+1)]);
    float df = t - f_old[IDX(i, j)];
    f[IDX(i,j)] = t;
    // Store squared difference in error array for reduction
    error_array[IDX(i,j)] = df * df;
  }
  else if (i < N && j < N) {
    // For points not updated, set error_array to 0
    error_array[IDX(i,j)] = 0.0f;
  }
}

__global__ void copy_kernel(float* f_old, const float* f) {
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  int j = blockIdx.y * blockDim.y + threadIdx.y;

  if (i < N && j < N) {
    if (i >= 1 && i <= N-2 && j >= 1 && j <= N-2)
      f_old[IDX(i,j)] = f[IDX(i,j)];
  }
}

__global__ void reduce_error(float* error_array, float* error_result) {
  // Block-wide reduction in shared memory
  __shared__ float sdata[256];
  unsigned int tid = threadIdx.x;
  unsigned int i = blockIdx.x * blockDim.x * 2 + threadIdx.x;

  float sum = 0.0f;
  if (i < N*N)
    sum += error_array[i];
  if (i + blockDim.x < N*N)
    sum += error_array[i + blockDim.x];

  sdata[tid] = sum;
  __syncthreads();

  // Reduce in shared memory
  for (unsigned int s = blockDim.x / 2; s > 0; s >>=1) {
    if (tid < s)
      sdata[tid] += sdata[tid + s];
    __syncthreads();
  }

  // Write result for this block to global memory
  if (tid == 0)
    error_result[blockIdx.x] = sdata[0];
}

int main () {
  auto start_time = std::chrono::steady_clock::now();

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  initialize_data(f);
  initialize_data(f_old);

  float *d_f, *d_f_old, *d_error_array, *d_error_intermediate;
  cudaMalloc(&d_f, N * N * sizeof(float));
  cudaMalloc(&d_f_old, N * N * sizeof(float));
  cudaMalloc(&d_error_array, N * N * sizeof(float));

  // Maximum number of blocks for reduction, for N*N elements
  int threads_per_block = 256;
  int blocks_reduction = (N*N + threads_per_block * 2 - 1) / (threads_per_block * 2);
  cudaMalloc(&d_error_intermediate, blocks_reduction * sizeof(float));

  cudaMemcpy(d_f, f, N * N * sizeof(float), cudaMemcpyHostToDevice);
  cudaMemcpy(d_f_old, f_old, N * N * sizeof(float), cudaMemcpyHostToDevice);

  const int max_iters = 10000;
  int num_iters = 0;

  dim3 threads(16,16);
  dim3 blocks((N-2 + threads.x - 1)/threads.x, (N-2 + threads.y - 1)/threads.y);
  dim3 blocks_full((N + threads.x - 1)/threads.x, (N + threads.y - 1)/threads.y);

  while (error > tolerance && num_iters < max_iters) {
    // Reset error to 0 on host
    error = 0.0f;

    jacobi_iteration<<<blocks, threads>>>(d_f_old, d_f, d_error_array);
    cudaDeviceSynchronize();

    // Reduce error_array to single error value
    // First reduction step
    reduce_error<<<blocks_reduction, threads_per_block>>>(d_error_array, d_error_intermediate);
    cudaDeviceSynchronize();

    // If more than one block, reduce again on host or device
    int s = blocks_reduction;
    float* d_in = d_error_intermediate;
    float* d_out;
    cudaMalloc(&d_out, sizeof(float) * ((s + threads_per_block*2 - 1)/(threads_per_block*2)));
    while (s > 1) {
      int nb = (s + threads_per_block*2 - 1)/(threads_per_block*2);
      reduce_error<<<nb, threads_per_block>>>(d_in, d_out);
      cudaDeviceSynchronize();
      s = nb;
      float* tmp = d_in;
      d_in = d_out;
      d_out = tmp;
    }

    // Copy final result to host
    float error_sum = 0.0f;
    cudaMemcpy(&error_sum, d_in, sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_out);

    error = sqrtf(error_sum / (N * N));

    copy_kernel<<<blocks_full, threads>>>(d_f_old, d_f);
    cudaDeviceSynchronize();

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  cudaMemcpy(f, d_f, N * N * sizeof(float), cudaMemcpyDeviceToHost);

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    cudaFree(d_f);
    cudaFree(d_f_old);
    cudaFree(d_error_array);
    cudaFree(d_error_intermediate);
    free(f);
    free(f_old);
    return -1;
  }

  cudaFree(d_f);
  cudaFree(d_f_old);
  cudaFree(d_error_array);
  cudaFree(d_error_intermediate);

  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
